`,m.jsx(c.code,{children:"useEffect"})," is the perfect place to initialize canvas drawing objects, attach event listeners for clicks, and kick off the game loop. But before we can initialize the game objects, we have to define their object types. So I created classes for each major entity in my game. Here's an example for the ",m.jsx(c.code,{children:"GameMap"}),":"]}),`
`,m.jsx(c.pre,{children:m.jsx(c.code,{className:"language-tsx",children:`// ./Components/GameMap.tsx
// GameMap - represents the tile map of the game world.
export class GameMap {
  tsize: number; // tile size in px
  cols: number;
  rows: number;
  tiles: number[];
  length: number;

  constructor(tsize: number = 64, cols: number = 888, rows: number = 2) {
    this.tsize = tsize;
    this.cols = cols;
    this.rows = rows;

    this.tiles = new Array(this.cols * this.rows);
    this.tiles.fill(0, 0, this.cols);
    this.tiles.fill(1, this.cols);
    this.length = cols * tsize;
  }

  // getTile
  // Gets the tile number to grab the correct sprite from the sprite sheet
  // @param col - the column number of the GameMap
  // @param row - the row number of the GameMap
  // @returns - the tile index number (0,1,2...?) at the specified column and row, or undefined if the coordinates are out of bounds
  getTile(col: number, row: number): number | undefined {
    if (col < 0 || col >= this.cols || row < 0 || row >= this.rows) {
      return undefined;
    } 
    return this.tiles[row * this.cols + col];
  }
}
`})}),`
